-- Crear tabla
create table if not exists workouts (
  id          serial primary key,
  semana      int not null,
  km_sem      int not null,
  dia         text,
  fecha       date not null,
  tipo        text not null,
  sesion      text,
  descripcion text,
  detalle     text
);

-- Insertar datos del plan 21K (22 semanas)

-- Habilitar RLS y política de lectura pública
alter table workouts enable row level security;
create policy "allow_public_read" on workouts for select using (true);